INSERT INTO scenario_questions (id, scenario_id, question_text, question_translation, order_index, keywords) VALUES
('int_q1', 'frontend', 'That is wonderful. Since you mentioned React, can you explain the critical differences between Server Components and Client Components in React 19, and when to use each?', '太赞了。既然你提到了 React，你能解释一下 React 19 中服务端组件和客户端组件的关键区别，以及何时使用它们吗？', 1, '[]'),
('int_q2', 'frontend', 'Excellent clarity. Now, regarding CSS and design systems, how do you manage utility-first styles in Tailwind CSS to maintain highly modular and customizable responsive UI layers?', '极其清晰的表述。那么，有关 CSS 和设计系统，你如何管理 Tailwind CSS 中的实用优先样式，以维护高度模块化的响应式 UI 界面？', 2, '[]'),
('int_q3', 'frontend', 'Perfect. Finally, in high-traffic applications, how do you diagnostic and optimize slow re-renders using standard React dev tools or profiling hooks?', '完美。最后一个问题，在高流量应用中，你如何通过开发者工具诊断并优化缓慢的重绘现象？', 3, '[]'),
('res_q1', 'restaurant', 'Excellent choice. Our chef recommends the pan-seared ribeye steak or the creamy garlic seafood pasta today. What would you like to have for your main course?', '优秀的选项。我们的大厨今天推荐香煎肋眼牛排或奶油蒜蓉海鲜面。您的主菜想吃点什么呢？', 1, '[]'),
('res_q2', 'restaurant', 'Perfect! And how would you like your steak done? We also offer various delicious sides like truffle fries or roasted asparagus.', '完美！您的牛排需要几分熟？我们还提供黑松露薯条或烤芦笋等多种可口配菜。', 2, '[]'),
('con_q1', 'conference', 'That sounds promising. However, our user engagement rate in some markets saw a slight decline. What adjustments should we introduce in the upcoming sprint to optimize this?', '这听起来很有前景。然而，我们在某些市场的用户参与率出现了轻微下滑。在接下来的迭代中，我们应该引入哪些调整来优化这一点？', 1, '[]'),
('con_q2', 'conference', 'Great suggestions. Lets compile these into our roadmap. Any other concerns or updates regarding our server scaling capability before we wrap up?', '极好的建议。我们将把这些整理进我们的路线图。在结束会议前，关于我们服务器扩容能力，大家还有其他疑问或更新汇报吗？', 2, '[]');